-- Update department head_doctor_name
UPDATE departments d SET head_doctor_name = 'Dr. ' || sub.first_name || ' ' || sub.last_name
FROM (
  SELECT DISTINCT ON (department) department, first_name, last_name
  FROM doctors ORDER BY department, experience_years DESC
) sub WHERE d.name = sub.department;
